@@ -646,9 +649,9 @@ static bool processOverflowIntrinsic(WithOverflowInst *WO, LazyValueInfo *LVI) {
   setDeducedOverflowingFlags(NewOp, Opcode, NSW, NUW);

   StructType *ST = cast<StructType>(WO->getType());
